  router: appRouter,
  title: 'My API',
  description: 'My API Description',
  version: '1.0.0',
  baseUrl: 'http://localhost:3000/api',
});

fs.writeFileSync('openapi.json', JSON.stringify(openApiDocument, null, 2));
console.log('OpenAPI document generated at openapi.json');
